import{_ as a,o as s,c as t,a3 as r}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"65. Special Disaster Leave","description":"","frontmatter":{"title":"65. Special Disaster Leave","eba":"Health Allied & Managers Admin 2021-2025","topics":["leave","personal-leave","employment"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/leave/65-special-disaster-leave.md","filePath":"ebas/has-managers-admin/common-terms/leave/65-special-disaster-leave.md"}'),o={name:"ebas/has-managers-admin/common-terms/leave/65-special-disaster-leave.md"};function i(l,e,n,p,m,d){return s(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="_65-special-disaster-leave" tabindex="-1">65. Special Disaster Leave <a class="header-anchor" href="#_65-special-disaster-leave" aria-label="Permalink to &quot;65. Special Disaster Leave&quot;">​</a></h1><p><strong>65.1</strong> Special disaster leave of up to 3 days per calendar year is payable where:</p><p><strong>(a)</strong> the Employee is a full time or part time employee;</p><p><strong>(b)</strong> Personal Leave is not available either because the Employee has exhausted the accrual or the circumstance does not qualify for Personal Leave; and</p><p><strong>(c)</strong> the Employee is unable to attend work due to a disaster (such as fire or flood) where:</p><p><strong>(i)</strong> the Employee&#39;s residence is damaged or under imminent threat of major damage;</p><p><strong>(ii)</strong> the lives or safety of their immediate family or household members are threatened; or</p><p><strong>(iii)</strong> there is a formal closure, flooding or other unusual danger of the use of a road(s) which is the Employee&#39;s normal travel route to work and no alternative practicable travel route is available.</p><p><strong>(d)</strong> Special disaster leave is non-cumulative.</p><p>Plain language terms: disaster leave, emergency leave, flood leave, bushfire leave.</p>',10)])])}const v=a(o,[["render",i]]);export{h as __pageData,v as default};
